# src/experiment/experiment_runner.py
# Project 5: Recognition using Deep Networks
# Author: Krushna Sanjay Sharma
# Description: ExperimentRunner executes all experiment configurations
#              generated by ExperimentConfig, trains each variant, records
#              results, and saves a CSV log for analysis.

import time
import csv
import os
from pathlib import Path
from typing import List

import torch
import torch.optim as optim

from src.network.transformer_network import NetTransformer, NetConfig
from src.data.fashion_loader         import FashionMNISTLoader
from src.training.trainer            import Trainer
from src.evaluation.evaluator        import Evaluator
from src.experiment.experiment_config import ExperimentConfig, ExperimentResult


class ExperimentRunner:
    """
    Executes the hyperparameter sweep defined by ExperimentConfig.

    For each configuration:
        1. Builds a NetTransformer with the given hyperparameters
        2. Trains for the configured number of epochs
        3. Evaluates on the Fashion MNIST test set
        4. Records accuracy, training time, and loss
        5. Saves results to a CSV file after every run (crash-safe)

    Author: Krushna Sanjay Sharma
    """

    def __init__(
        self,
        device:     torch.device,
        data_dir:   str = "./data",
        output_dir: str = "./outputs",
        results_csv: str = "task5_results.csv",
    ):
        """
        Initialises the runner.

        Args:
            device      (torch.device): Target compute device.
            data_dir    (str):          Directory for Fashion MNIST cache.
            output_dir  (str):          Directory for CSV and plots.
            results_csv (str):          Filename for the results CSV.
        """
        self._device      = device
        self._output_dir  = Path(output_dir)
        self._output_dir.mkdir(parents=True, exist_ok=True)
        self._csv_path    = self._output_dir / results_csv
        self._results: List[ExperimentResult] = []

        # Pre-load Fashion MNIST once — reused across all runs
        print("  [ExperimentRunner] Loading Fashion MNIST...")
        self._data_loader = FashionMNISTLoader(data_dir=data_dir, batch_size=64)

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def run(self, configs: list) -> List[ExperimentResult]:
        """
        Executes all experiment configurations in order.

        Saves results to CSV after every run so progress is not lost
        if the sweep is interrupted.

        Args:
            configs (list): List of config dicts from ExperimentConfig.

        Returns:
            List[ExperimentResult]: All collected results.
        """
        total = len(configs)
        print(f"\n  [ExperimentRunner] Starting sweep: {total} runs\n")

        # Write CSV header
        self._init_csv()

        for i, cfg in enumerate(configs):
            print(f"\n  {'='*55}")
            print(f"  Run {i+1}/{total} | Phase: {cfg['phase']}")
            print(f"  patch={cfg['patch_size']}  embed={cfg['embed_dim']}  "
                  f"depth={cfg['depth']}  epochs={cfg['epochs']}")
            print(f"  {'='*55}")

            result = self._run_single(cfg)
            self._results.append(result)
            self._append_csv(result)

            print(f"  --> Accuracy: {result.test_accuracy:.2f}%  "
                  f"Time: {result.train_time_s:.1f}s")

        print(f"\n  [ExperimentRunner] Sweep complete. Results saved to: {self._csv_path}")
        return self._results

    def get_results(self) -> List[ExperimentResult]:
        """Returns all collected experiment results."""
        return self._results

    # ------------------------------------------------------------------
    # Private helpers
    # ------------------------------------------------------------------

    def _run_single(self, cfg: dict) -> ExperimentResult:
        """
        Trains and evaluates one configuration.

        Builds a fresh NetTransformer, trains it for cfg['epochs'] epochs,
        evaluates on the test set, and returns the result.

        Args:
            cfg (dict): Configuration dict with patch_size, embed_dim,
                        depth, epochs, batch_size, lr, weight_decay.

        Returns:
            ExperimentResult with accuracy, time, and loss recorded.
        """
        # Build NetConfig for this run
        net_config = NetConfig(
            patch_size   = cfg["patch_size"],
            embed_dim    = cfg["embed_dim"],
            depth        = cfg["depth"],
            epochs       = cfg["epochs"],
            batch_size   = cfg["batch_size"],
            lr           = cfg["lr"],
            weight_decay = cfg["weight_decay"],
            device       = str(self._device),
        )

        # Build fresh model
        model = NetTransformer(net_config).to(self._device)

        # AdamW optimiser — standard for transformers
        optimiser = optim.AdamW(
            model.parameters(),
            lr           = cfg["lr"],
            weight_decay = cfg["weight_decay"],
        )

        trainer   = Trainer(model=model, optimiser=optimiser,
                            device=self._device, log_interval=999)  # suppress batch logs
        evaluator = Evaluator(model=model, device=self._device)

        # Train and time
        start = time.time()
        for epoch in range(1, cfg["epochs"] + 1):
            trainer.train_epoch(self._data_loader.train_loader, epoch_num=epoch)

        elapsed = time.time() - start

        # Evaluate on test set
        test_acc = evaluator.evaluate(self._data_loader.test_loader)

        return ExperimentResult(
            run_id        = cfg["run_id"],
            phase         = cfg["phase"],
            patch_size    = cfg["patch_size"],
            embed_dim     = cfg["embed_dim"],
            depth         = cfg["depth"],
            test_accuracy = test_acc,
            train_time_s  = elapsed,
            epochs        = cfg["epochs"],
            final_loss    = trainer.train_losses[-1],
        )

    def _init_csv(self) -> None:
        """Writes the CSV header row."""
        with open(self._csv_path, "w", newline="") as f:
            writer = csv.writer(f)
            writer.writerow([
                "run_id", "phase", "patch_size", "embed_dim", "depth",
                "epochs", "test_accuracy", "train_time_s", "final_loss",
            ])

    def _append_csv(self, result: ExperimentResult) -> None:
        """Appends one result row to the CSV (crash-safe incremental write)."""
        with open(self._csv_path, "a", newline="") as f:
            writer = csv.writer(f)
            writer.writerow([
                result.run_id,
                result.phase,
                result.patch_size,
                result.embed_dim,
                result.depth,
                result.epochs,
                f"{result.test_accuracy:.4f}",
                f"{result.train_time_s:.1f}",
                f"{result.final_loss:.4f}",
            ])